--
-- Name: patients patients_clinic_id_patient_id_key; Type: CONSTRAINT; Schema: public; Owner: postgres
--

ALTER TABLE ONLY public.patients
    ADD CONSTRAINT patients_clinic_id_patient_id_key UNIQUE (clinic_id, patient_id);


--
-- Name: patients patients_pkey; Type: CONSTRAINT; Schema: public; Owner: postgres
--

ALTER TABLE ONLY public.patients
    ADD CONSTRAINT patients_pkey PRIMARY KEY (id);


--
-- Name: idx_patients_clinic_id; Type: INDEX; Schema: public; Owner: postgres
--

CREATE INDEX idx_patients_clinic_id ON public.patients USING btree (clinic_id);


--
-- Name: idx_patients_patient_id; Type: INDEX; Schema: public; Owner: postgres
--

CREATE INDEX idx_patients_patient_id ON public.patients USING btree (clinic_id, patient_id);


--
-- Name: patients update_patients_updated_at; Type: TRIGGER; Schema: public; Owner: postgres
--

CREATE TRIGGER update_patients_updated_at BEFORE UPDATE ON public.patients FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();


--
-- Name: patients patients_clinic_id_fkey; Type: FK CONSTRAINT; Schema: public; Owner: postgres
--

ALTER TABLE ONLY public.patients
    ADD CONSTRAINT patients_clinic_id_fkey FOREIGN KEY (clinic_id) REFERENCES public.clinics(id) ON DELETE CASCADE;


--
-- Name: patients Office staff and billing staff can delete patients; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Office staff and billing staff can delete patients" ON public.patients FOR DELETE USING ((public.is_super_admin() OR ((clinic_id IN ( SELECT unnest(users.clinic_ids) AS unnest
   FROM public.users
  WHERE (users.id = auth.uid()))) AND (EXISTS ( SELECT 1
   FROM public.users
  WHERE ((users.id = auth.uid()) AND (users.role = ANY (ARRAY['office_staff'::text, 'billing_staff'::text, 'admin'::text, 'super_admin'::text]))))))));


--
-- Name: patients Office staff and billing staff can insert patients; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Office staff and billing staff can insert patients" ON public.patients FOR INSERT WITH CHECK ((public.is_super_admin() OR ((clinic_id IN ( SELECT unnest(users.clinic_ids) AS unnest
   FROM public.users
  WHERE (users.id = auth.uid()))) AND (EXISTS ( SELECT 1
   FROM public.users
  WHERE ((users.id = auth.uid()) AND (users.role = ANY (ARRAY['office_staff'::text, 'billing_staff'::text, 'admin'::text, 'super_admin'::text]))))))));


--
-- Name: patients Office staff and billing staff can update patients; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Office staff and billing staff can update patients" ON public.patients FOR UPDATE USING ((public.is_super_admin() OR ((clinic_id IN ( SELECT unnest(users.clinic_ids) AS unnest
   FROM public.users
  WHERE (users.id = auth.uid()))) AND (EXISTS ( SELECT 1
   FROM public.users
  WHERE ((users.id = auth.uid()) AND (users.role = ANY (ARRAY['office_staff'::text, 'billing_staff'::text, 'admin'::text, 'super_admin'::text]))))))));


--
-- Name: patients Users can view patients in their clinics; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Users can view patients in their clinics" ON public.patients FOR SELECT USING (((clinic_id IN ( SELECT unnest(users.clinic_ids) AS unnest
   FROM public.users
  WHERE (users.id = auth.uid()))) OR public.is_super_admin()));


--
-- Name: patients; Type: ROW SECURITY; Schema: public; Owner: postgres
--

ALTER TABLE public.patients ENABLE ROW LEVEL SECURITY;

--
-- Name: TABLE patients; Type: ACL; Schema: public; Owner: postgres
--

GRANT ALL ON TABLE public.patients TO anon;
GRANT ALL ON TABLE public.patients TO authenticated;
GRANT ALL ON TABLE public.patients TO service_role;


